import{_ as l,o as e,c as i,a0 as t}from"./chunks/framework.CSGB4SNl.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"java/eight-legged essay/java-hot200-day03.md","filePath":"java/eight-legged essay/java-hot200-day03.md"}'),o={name:"java/eight-legged essay/java-hot200-day03.md"};function r(s,a,d,n,h,c){return e(),i("div",null,[...a[0]||(a[0]=[t('<h4 id="为什么需要消息队列" tabindex="-1">为什么需要消息队列 <a class="header-anchor" href="#为什么需要消息队列" aria-label="Permalink to &quot;为什么需要消息队列&quot;">​</a></h4><ol><li>互联网业务的不断扩张，用户量不断增大，资源的合理合时利用，服务间的解耦，流量洪峰的控制</li><li>功能：异步处理、服务解耦、流量控制</li><li>带来的问题：一致性问题，中间件宕机问题、系统复杂性提高</li><li>某个服务的相关消息塞入消息队列，下游服务谁要使用谁就订阅</li></ol><h4 id="mysql的事务隔离级别有哪些" tabindex="-1">mysql的事务隔离级别有哪些 <a class="header-anchor" href="#mysql的事务隔离级别有哪些" aria-label="Permalink to &quot;mysql的事务隔离级别有哪些&quot;">​</a></h4><ol><li>读未提交、读已提交、可重复读、串行化</li><li>读未提交：就是一个事务读到另一个事务还未提交的数据，可能之后就会回滚了，读到的是脏数据</li><li>读已提交：只能看到别的事务已经提交的数据，可能两次读取到的数据还是会不一致，因为两次读之间数据可能又会被修改</li><li>可重复读：就是事务开始后不管其它事务怎么提交，看到的永远是事务开始时那一刻的快照，可能还是会有幻读存在，两次范围查询的行数可能不同</li><li>串行化，最严格的，必须让事务一个个排队执行，关闭所有并发，把普通的select都加上共享锁，杜绝所有并发问题，但是性能很差</li><li>为啥mysql选择可重复读呢：因为在主从复制情况下，主库和从库两次读到的数据可能不同，binlog会记录最先提交的那个事务按顺序来，这就导致如果我先del &lt;10的数据没提交，再inseter 5提交，复制到从库时就会没了5，而主库有5两次读到的就不一样了</li><li>读已提交就不用维护undolog那样长的版本链，且长事务跑起来内存消耗大</li></ol><h4 id="消息队列的模型有哪些" tabindex="-1">消息队列的模型有哪些 <a class="header-anchor" href="#消息队列的模型有哪些" aria-label="Permalink to &quot;消息队列的模型有哪些&quot;">​</a></h4><ol><li>队列模型：一个生产者生产消息，多个消费者竞争消费消息，且只能被一个消费者消费掉，适用于日志分发，发布/订阅模型：一个生产者向topic发送消息，订阅者同时收到消息副本适用广播通知和日志分发</li></ol><h4 id="常见的几种设计模式和应用场景" tabindex="-1">常见的几种设计模式和应用场景 <a class="header-anchor" href="#常见的几种设计模式和应用场景" aria-label="Permalink to &quot;常见的几种设计模式和应用场景&quot;">​</a></h4><ol><li>比如单例模式，确保一个类只有一个实例，且全局只提供一个访问点，比如支付场景需要对接多方支付平台-支付宝、微信等，还有全局配置，数据库连接池等</li><li>还有简单工厂模式选择支付渠道，传入alipay得到支付宝的实现类，传入wechat得到微信支付的实现类</li><li>模板模式：父类定义支付流程，子类实现具体逻辑</li></ol>',8)])])}const u=l(o,[["render",r]]);export{m as __pageData,u as default};
